$pmv_seed$::jsonb) as record (
    id text,
    source text,
    original_id text,
    start_time timestamptz,
    completion_time timestamptz,
    email text,
    form_name text,
    last_modified_time timestamptz,
    reporter_name text,
    report_date date,
    machine_type text,
    machine_number text,
    machine_status text,
    ips_battery text,
    checklist jsonb,
    damaged_components jsonb,
    idle_reason text,
    assistant_notes text,
    sync_status text,
    updated_at timestamptz
  )
)
insert into public.pmv_records (
  id,
  source,
  original_id,
  start_time,
  completion_time,
  email,
  form_name,
  last_modified_time,
  reporter_name,
  report_date,
  machine_type,
  machine_number,
  machine_status,
  ips_battery,
  checklist,
  damaged_components,
  idle_reason,
  assistant_notes,
  sync_status,
  updated_at
)
select
  id,
  coalesce(nullif(source, ''), 'Excel PMV historical'),
  original_id,
  start_time,
  completion_time,
  email,
  form_name,
  last_modified_time,
  reporter_name,
  report_date,
  machine_type,
  coalesce(machine_number, ''),
  machine_status,
  ips_battery,
  coalesce(checklist, '{}'::jsonb),
  coalesce(damaged_components, '[]'::jsonb),
  idle_reason,
  assistant_notes,
  sync_status,
  coalesce(updated_at, now())
from seed_records
where id is not null
  and reporter_name is not null
  and report_date is not null
  and machine_status in ('working', 'breakdown', 'idle')
on conflict (id) do update set
  source = excluded.source,
  original_id = excluded.original_id,
  start_time = excluded.start_time,
  completion_time = excluded.completion_time,
  email = excluded.email,
  form_name = excluded.form_name,
  last_modified_time = excluded.last_modified_time,
  reporter_name = excluded.reporter_name,
  report_date = excluded.report_date,
  machine_type = excluded.machine_type,
  machine_number = excluded.machine_number,
  machine_status = excluded.machine_status,
  ips_battery = excluded.ips_battery,
  checklist = excluded.checklist,
  damaged_components = excluded.damaged_components,
  idle_reason = excluded.idle_reason,
  assistant_notes = excluded.assistant_notes,
  sync_status = excluded.sync_status;

select
  count(*) as historical_pmv_records
from public.pmv_records
where source = 'Excel PMV historical';
